import React from "react";
import styled from "styled-components";
import HeaderImage from "../utils/Images/Header.png";
import Button from "./Button";

const HeroContainer = styled.div`
  position: relative;
  min-height: 520px;
  height: 74vh;
  max-width: 1400px;
  margin: 0 auto;
  border-radius: 30px;
  overflow: hidden;
  box-shadow: ${({ theme }) => theme.shadow_2xl};
  border: 1px solid ${({ theme }) => theme.border};
  @media (max-width: 768px) {
    min-height: 460px;
    height: auto;
  }
`;

const Slide = styled.div`
  position: relative;
  min-height: 520px;
  height: 100%;
  background: linear-gradient(135deg, rgba(102, 126, 234, 0.9) 0%, rgba(118, 75, 162, 0.9) 100%), url(${props => props.bg});
  background-size: cover;
  background-position: center;
  background-blend-mode: overlay;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  color: white;
  @media (max-width: 768px) {
    min-height: 460px;
    padding: 1.5rem 1rem;
  }
`;

const SlideContent = styled.div`
  max-width: 700px;
  padding: 2.6rem;
  background: rgba(255, 255, 255, 0.15);
  backdrop-filter: blur(20px);
  border-radius: 24px;
  border: 1px solid rgba(255, 255, 255, 0.3);
  animation: fadeIn 0.8s ease-out;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
  
  @keyframes fadeIn {
    from { opacity: 0; transform: translateY(30px); }
    to { opacity: 1; transform: translateY(0); }
  }
`;

const SlideTitle = styled.h1`
  font-size: clamp(2.5rem, 5vw, 3.5rem);
  font-weight: 800;
  margin-bottom: 1rem;
  color: white;
  text-shadow: 2px 2px 4px rgba(0,0,0,0.2);
`;

const SlideSubtitle = styled.p`
  font-size: 1.1rem;
  margin-bottom: 2rem;
  opacity: 0.95;
  line-height: 1.6;
`;

const HeroSlider = () => (
  <HeroContainer>
    <Slide bg={HeaderImage}>
      <SlideContent>
        <SlideTitle>Premium Shopping Experience</SlideTitle>
        <SlideSubtitle>Discover luxury brands with fast delivery and best prices</SlideSubtitle>
        <Button text="Shop Now" outlined full />
      </SlideContent>
    </Slide>
  </HeroContainer>
);

export default HeroSlider;
