import React, { useEffect, useState } from "react";
import styled from "styled-components";
import HeroSlider from "../components/HeroSlider";
import Stats from "../components/Stats";
import Testimonials from "../components/Testimonials";
import { category } from "../utils/data";
import ProductCategoryCard from "../components/cards/ProductCategoryCard";
import ProductCard from "../components/cards/ProductCard";
import { getAllProducts } from "../api";
import { useDispatch } from "react-redux";
import { openSnackbar } from "../redux/reducers/snackbarSlice";

const Container = styled.div`
  padding: 2.5rem 2rem 6rem;
  min-height: calc(100vh - 90px);
  display: flex;
  flex-direction: column;
  gap: 4.5rem;
`;

const Section = styled.section`
  max-width: 1400px;
  margin: 0 auto;
  padding: 0 1.5rem;
  width: 100%;
`;

const SectionHeader = styled.div`
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 1rem;
  margin-bottom: 2rem;
  flex-wrap: wrap;
`;

const CategoryWrapper = styled.div`
  overflow-x: auto;
  display: flex;
  gap: 24px;
  padding-bottom: 1rem;
  scrollbar-width: thin;
  &::-webkit-scrollbar {
    height: 6px;
  }
  &::-webkit-scrollbar-thumb {
    background: ${({ theme }) => theme.primary_gradient};
    border-radius: 3px;
  }
`;

const Title = styled.h2`
  font-size: clamp(1.9rem, 4vw, 2.8rem);
  font-weight: 700;
  text-align: ${({ center }) => (center ? "center" : "left")};
  color: ${({ theme }) => theme.text_primary};
  line-height: 1.2;
  position: relative;

  &::after {
    content: "";
    display: ${({ center }) => (center ? "block" : "none")};
    width: 64px;
    height: 4px;
    background: ${({ theme }) => theme.primary_gradient};
    margin: 1rem auto 0;
    border-radius: 2px;
  }
`;

const SectionSubtext = styled.p`
  color: ${({ theme }) => theme.text_secondary};
  font-size: 1rem;
  max-width: 560px;
`;

const FeaturedBadge = styled.span`
  background: ${({ theme }) => theme.bgLight};
  color: ${({ theme }) => theme.primary};
  border: 1px solid ${({ theme }) => theme.border};
  border-radius: 999px;
  padding: 0.45rem 0.85rem;
  font-size: 0.82rem;
  font-weight: 600;
  letter-spacing: 0.2px;
`;

const ProductGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 2rem;
  max-width: 1400px;
  margin: 0 auto;
`;

const LoadingGrid = styled(ProductGrid)`
  min-height: 240px;
`;

const LoadingCard = styled.div`
  border-radius: 24px;
  border: 1px solid ${({ theme }) => theme.border};
  background: ${({ theme }) => theme.card_light};
  min-height: 220px;
  animation: pulse 1.4s ease-in-out infinite;

  @keyframes pulse {
    0% {
      opacity: 0.6;
    }
    50% {
      opacity: 1;
    }
    100% {
      opacity: 0.6;
    }
  }
`;

const NewsletterSection = styled.div`
  background: ${({ theme }) => theme.glass_bg};
  backdrop-filter: blur(20px);
  padding: 3.2rem 2rem;
  border-radius: 30px;
  text-align: center;
  border: 1px solid ${({ theme }) => theme.border};
  box-shadow: ${({ theme }) => theme.shadow_lg};
  max-width: 880px;
  margin: 0 auto;
`;

const NewsletterTitle = styled.h3`
  font-size: clamp(1.5rem, 2.8vw, 2rem);
  margin-bottom: 0.9rem;
  color: ${({ theme }) => theme.text_primary};
`;

const NewsletterDescription = styled.p`
  font-size: 1rem;
  margin-bottom: 1.8rem;
  opacity: 0.9;
  color: ${({ theme }) => theme.text_secondary};
`;

const NewsletterActions = styled.div`
  display: flex;
  gap: 1rem;
  justify-content: center;
  flex-wrap: wrap;
`;

const NewsletterInput = styled.input`
  padding: 0.95rem 1.3rem;
  border: 1px solid ${({ theme }) => theme.border};
  border-radius: 50px;
  background: ${({ theme }) => theme.bgLight};
  width: 320px;
  max-width: 100%;
  color: ${({ theme }) => theme.text_primary};
  outline: none;
  transition: box-shadow 0.25s ease, border-color 0.25s ease;
  &::placeholder {
    color: ${({ theme }) => theme.text_tertiary};
  }
  &:focus {
    border-color: ${({ theme }) => theme.primary};
    box-shadow: ${({ theme }) => theme.shadow_sm};
  }
`;

const NewsletterButton = styled.button`
  padding: 0.95rem 1.8rem;
  background: ${({ theme }) => theme.primary_gradient};
  color: white;
  border: none;
  border-radius: 50px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  &:hover {
    transform: translateY(-2px);
    box-shadow: ${({ theme }) => theme.shadow_lg};
  }
`;

const Home = () => {
  const dispatch = useDispatch();
  const [loading, setLoading] = useState(false);
  const [products, setProducts] = useState([]) ;

  const getProducts = async () => {
    setLoading(true);
    try {
      const res = await getAllProducts();
      setProducts(res.data);
    } catch (error) {
      setProducts([]);
      dispatch(
        openSnackbar({
          message: "Khong the ket noi den server/DB.",
          severity: "error",
        })
      );
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    getProducts();
  }, []);
  return (
    <Container>
      <Section>
        <HeroSlider />
      </Section>
      <Stats />
      <Section>
        <SectionHeader>
          <div>
            <Title>Shop by Categories</Title>
            <SectionSubtext>
              Curated collections to help you find the right products faster.
            </SectionSubtext>
          </div>
          <FeaturedBadge>Popular picks</FeaturedBadge>
        </SectionHeader>
        <CategoryWrapper>
          {category.map((category, index) => (
            <ProductCategoryCard key={index} category={category} />
          ))}
        </CategoryWrapper>
      </Section>
      <Section>
        <SectionHeader>
          <div>
            <Title>Our Bestsellers</Title>
            <SectionSubtext>
              Handpicked products loved by customers across all categories.
            </SectionSubtext>
          </div>
          <FeaturedBadge>Updated daily</FeaturedBadge>
        </SectionHeader>
        {loading ? (
          <LoadingGrid>
            {Array.from({ length: 8 }).map((_, index) => (
              <LoadingCard key={index} />
            ))}
          </LoadingGrid>
        ) : (
          <ProductGrid>
            {products.slice(0, 8).map((product) => (
              <ProductCard key={product._id} product={product} />
            ))}
          </ProductGrid>
        )}
      </Section>
      <Testimonials />
      <NewsletterSection>
        <NewsletterTitle>Ready to shop?</NewsletterTitle>
        <NewsletterDescription>
          Subscribe and get notified for new arrivals
        </NewsletterDescription>
        <NewsletterActions>
          <NewsletterInput placeholder="Enter your email" />
          <NewsletterButton>Subscribe</NewsletterButton>
        </NewsletterActions>
      </NewsletterSection>
    </Container>
  );
};

export default Home;
